What does this program print?

```cpp
#include <iostream>

int main() {
    int arr[4]{ 10, 20, 30, 40 };
    int* p = arr + 1;
    std::cout << *p       << '\n';
    std::cout << *(p + 2) << '\n';
    std::cout << p[0]     << '\n';
}
```

What does this program print?

```cpp
#include <iostream>

int main() {
    int nums[3]{ 5, 10, 15 };
    int* end = nums + 3;
    int sum = 0;
    for (int* p = nums; p != end; ++p)
        sum += *p;
    std::cout << sum << '\n';
}
```

